import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { EquipsService } from '../../../services/equips.service';
import { EquipCategorias } from '../../../models/equip-categorias';
import { EquipCategoriaResposta } from '../../../models/equip-categoria-resposta';  // Importando o modelo da resposta

@Component({
  selector: 'app-ataque',
  templateUrl: './ataque.component.html',
  styleUrls: ['./ataque.component.css']
})
export class AtaqueComponent implements OnInit {
subcategorias: any;
exibirPopup(_t20: EquipCategorias) {
throw new Error('Method not implemented.');
}

  categorias = [
    { nome: 'Armas', link: '/arma' },
    { nome: 'Munição', link: '/municao' },
    { nome: 'Armas Simples', link: '/armas-simples' },
    { nome: 'Armas Marciais', link: '/armas-marciais' },
    { nome: 'Armas Corpo a Corpo', link: '/armas-corpo-a-corpo' },
    { nome: 'Armas a Distância', link: '/armas-a-distancia' }
  ];

  equipamentos: EquipCategorias[] = [];  // Tipando como EquipCategorias[], que é um array

  constructor(
    private route: ActivatedRoute,
    private equipsService: EquipsService
  ) {}

  ngOnInit(): void {
    // Exemplo: pegando o endpoint da URL
    const subcategoria = this.route.snapshot.paramMap.get('subcategoria')!;
    this.carregarEquipamentos(subcategoria);
  }

  carregarEquipamentos(subcategoria: string): void {
    this.equipsService.getEquipamentosPorSubcategoria(subcategoria).subscribe((resposta: EquipCategoriaResposta) => {
      console.log('Equipamentos carregados:', resposta.equipment);
      this.equipamentos = resposta.equipment; // Acessando o array de equipamentos
    });
  }
}
